function solve(sx: number, sy: number, tx: number, ty: number): number {
  // If starting point is the target, return 0
  if (sx === tx && sy === ty) return 0;

  // If target is not reachable, return -1
  if ((sx + sy) > (tx + ty) || (sx + sy) % 2 !== (tx + ty) % 2) {
    return -1;
  }

  let steps = 0;
  while (sx < tx || sy < ty) {
    const m = Math.max(sx, sy);
